import{_ as u}from"./Menu.179edc93.js";import{r as t,a as d,e,b as i,i as s,w as p,f as n,k as c,o as m}from"./entry.7b9f66e3.js";import{u as v}from"./composables.96d18f89.js";const h=""+new URL("app-fossile-poster.05331456.jpg",import.meta.url).href,g=""+new URL("teaser-video.f7f9bff0.mp4",import.meta.url).href,_=""+new URL("projet-lefossilemagique-methode-1.a8736f47.png",import.meta.url).href,f=""+new URL("experience-map.ef47138d.jpg",import.meta.url).href,b=""+new URL("parcours-utilisateur.525ae81e.mp4",import.meta.url).href,q={class:"banniere"},x=n('<div class="margium-l marge-haute-l"><div class="espacium"><h1>Le Fossile Magique</h1><div class="colonnes"><div class="colonne"><div class="projettitre">Contexte</div> Projet de Master 2 DGI \xE0 l&#39;UPHF<br> Septembre 2021 \xE0 juin 2022 </div><div class="colonne"><div class="projettitre">\xC9quipe</div><a href="https://www.behance.net/VianneyChantry" target="_blank">Vianney Chantry</a>, <a href="https://www.behance.net/talal_afyouni" target="_blank">Talal Afyouni</a></div><div class="colonne"><div class="projettitre">Distinction</div> Prim\xE9 \xE0 Cr\xE9aTalents 2022 </div><div class="colonne"><a href="https://fossilemagique.lucaslacroix.com" class="lienapp" target="_blank">Voir la web app</a></div></div></div></div>',1),L={class:"margium-l marge-haute-l marge-basse-l"},y={class:"espacium"},j={class:"coldroite"},w=e("p",null,"Notre projet de master 2 a pour objectif de cr\xE9er un dispositif interactif dans le champ des industries interactives et culturels. Nous avons choisi de travailler sur la mus\xE9ographie de la pal\xE9ontologie en choisissant la sc\xE9nographie de galerie de Paris. Une grande partie de ce projet a consist\xE9 \xE0 mener une recherche aupr\xE8s de parties prenantes, d\u2019analyse de l'existant, de test utilisateur et recherche de documentation sur la gamification et la gestion de projet UX. ",-1),N=e("h2",null,"Le serious game",-1),C=e("video",{width:"720",height:"405",controls:"",poster:h},[e("source",{src:g,type:"video/mp4"}),s(" Your browser does not support the video tag. ")],-1),P=e("p",null,"La galerie de pal\xE9ontologie a ouvert ses portes \xE0 la fin du 19\xE8me si\xE8cle. C'est un lieu historique o\xF9 la sc\xE9nographie a peu \xE9volu\xE9 au cours des si\xE8cles. Pour rendre la visite plus interactive tout en conservant la mus\xE9ographie actuelle, nous avons d\xE9velopp\xE9 une web-application narrative pour les visiteurs. ",-1),M=e("p",null,"Lorsque l'on visite une galerie, on est amen\xE9 \xE0 lire beaucoup d'encarts, ce qui est fastidieux et n'est pas toujours tr\xE8s adapt\xE9 au jeune public. Nous avons con\xE7u une application permettant de visiter la galerie \xE0 travers des activit\xE9s pour apprendre des notions de pal\xE9ontologie. Une affiche nous incite \xE0 utiliser l'application d\xE8s notre arriv\xE9e dans la galerie. On acc\xE8de \xE0 la web-app qui nous invite \xE0 suivre une histoire et des activit\xE9s \xE0 travers le mus\xE9e.",-1),U=e("h2",null,"M\xE9thodes et conduite de projet",-1),V=e("img",{src:_,loading:"lazy",alt:"Sch\xE9ma Double diamant du projet"},null,-1),k=e("br",null,null,-1),D=e("br",null,null,-1),F=e("br",null,null,-1),R=e("br",null,null,-1),B=e("br",null,null,-1),E=e("br",null,null,-1),T=e("br",null,null,-1),z=e("br",null,null,-1),I=e("br",null,null,-1),S=e("br",null,null,-1),A=e("ul",null,[e("li",null,"Probl\xE8me de compr\xE9hension de la promesse d'exp\xE9rience \u2192 changement d'onboarding"),e("li",null,"Interactions de certains jeux sont qualifi\xE9es de compliquer \u2192 simplification des interactions des jeux "),e("li",null,"Probl\xE8me d'engagement \u2192 \xC9laboration de narration et plus de gamification"),e("li",null,"Trop de personnages diff\xE9rents dans l'application \u2192 Un seul protagoniste ")],-1),G=e("br",null,null,-1),H=e("br",null,null,-1),Y=n('<img src="'+f+'" loading="lazy" alt="Exp\xE9rience map issue des tests utilisateurs"><p>La version 2 de l&#39;application \xE9tant d\xE9velopp\xE9, nous avons r\xE9alis\xE9 des tests utilisateur au mus\xE9e institue avec des r\xE9els visiteurs, nous avons dress\xE9 cette exp\xE9rience map avec leurs retours. Ce test de plus grande ampleur nous as permis de sortir piste d\u2019am\xE9lioration pour une future V3</p><h2>Narration</h2><p>Notre storytelling transforme le visiteur en h\xE9ros de l&#39;histoire, c&#39;est la premi\xE8re dynamique d&#39;engagement que l&#39;utilisateur rencontre.<br> Mary, jeune pal\xE9ontologue, d\xE9couvre un fossile d&#39;o\xF9 l&#39;esprit du temps s&#39;\xE9chappe. Celui-ci ouvre une faille qui menace le mus\xE9e. <br>L&#39;utilisateur doit aider Mary \xE0 refermer la faille en terminant les activit\xE9s et en gagnant le duel final.<br> Le design \xE0 l&#39;aspect doux et color\xE9, tout en restant dans une certaine sobri\xE9t\xE9, permet de cr\xE9er un v\xE9ritable engagement chez l&#39;utilisateur. Il \xE9vite \xE9galement de saturer l&#39;\xE9cran d&#39;\xE9l\xE9ments graphiques trop complexes.<br> Les personnages de Mary et de l&#39;esprit ont \xE9t\xE9 con\xE7us pour \xEAtre visuellement sympathiques et attachants. Mary permet par ailleurs la personnification du narrateur qu&#39;on retrouve au fil des activit\xE9s. </p><h2>Gamification</h2><p> Pour donner envie aux visiteurs de terminer l&#39;histoire et permettre l&#39;apprentissage par le jeu, notre application a recours \xE0 5 leviers d&#39;engagement : L&#39;envie de progression, l&#39;immersion, l&#39;autonomie, la curiosit\xE9 et le besoin de se d\xE9passer. <br>L&#39;envie de progression est appuy\xE9e par la collection de fragments du fossile \xE0 chaque activit\xE9 termin\xE9e et le fait de d\xE9bloquer les activit\xE9s suivantes jusqu&#39;\xE0 l&#39;esprit du temps. <br> L&#39;immersion est aussi un \xE9l\xE9ment d&#39;engagement de notre application, gr\xE2ce aux audios, nous arrivons \xE0 plonger l&#39;utilisateur dans une histoire fantaisiste. <br>L&#39;application g\xE8re le besoin d&#39;autonomie, en permettant \xE0 l&#39;utilisateur d&#39;\xEAtre ind\xE9pendant, de suivre l&#39;histoire \xE0 son rythme, d&#39;effectuer des choix qui auront une incidence sur la r\xE9ussite du jeu. Le besoin de se d\xE9passer est utilis\xE9 \xE0 chaque activit\xE9, ces derni\xE8res sont bas\xE9es sur le mod\xE8le &quot;apprentissage -&gt; challenge/\xE9valuation -&gt; r\xE9compense&quot;.<br>Ce syst\xE8me est \xE9galement utilis\xE9 avec le duel de fin </p><h2>Notions abord\xE9es</h2><p> Nous avons s\xE9lectionn\xE9 3 notions qui \xE9taient transposables \xE0 la vulgarisation et \xE0 la galerie de pal\xE9ontologie. <ul><li><h3>Fossilisation</h3>Pour \xE9voquer la notion de fossilisation, nous avons r\xE9alis\xE9 des vid\xE9os narratives. Elles sont entrecoup\xE9es d&#39;activit\xE9s interactives comme le nettoyage du fossile. La validation de cette partie consiste \xE0 replacer les \xE9tapes de la fossilisation dans l&#39;ordre. </li><li><h3>Repr\xE9sentation des animaux</h3>La notion de repr\xE9sentation a \xE9t\xE9 amen\xE9e sous forme d&#39;une frise accompagn\xE9e de narrations audio. Celle-ci contient des dessins au feutre de l&#39;iguanodon. Le style graphique sous forme de &quot;dessin au feutre&quot; rappelle \xE0 l&#39;utilisateur qu&#39;on parle de repr\xE9sentation hypoth\xE9tique de l&#39;animal. Cette partie se termine par 3 questions permettant de v\xE9rifier les connaissances des utilisateurs. </li><li><h3>\xC9volution</h3>Pour illustrer l&#39;\xE9volution, nous avons suivi le cas du mammouth. Nous avons \xE9labor\xE9 une vid\xE9o narrative ainsi qu&#39;une frise. Celle-ci montre l&#39;\xE9volution d&#39;une population de mammouths au cours du temps. Les connaissances sont ici v\xE9rifi\xE9es par un &quot;Vrai / Faux&quot; </li></ul></p><h2>Le parcours utilisateur</h2><video width="720" height="405" controls><source src="'+b+'" type="video/mp4"> Your browser does not support the video tag. </video>',10),W={__name:"le-fossile-magique",setup(O){const a=t("Le Fossile Magique - Lucas Lacroix"),o=t("Pour donner envie aux visiteurs de terminer l'histoire et permettre l'apprentissage par le jeu, notre application a recours \xE0 5 leviers d'engagement");return v({title:a,meta:[{name:"description",content:o}]}),(X,$)=>{const r=u,l=c;return m(),d("div",null,[e("div",q,[i(r),x]),e("article",L,[e("div",y,[e("div",j,[w,N,C,P,M,U,V,e("p",null,[s(" Le premier semestre du projet a \xE9t\xE9 men\xE9 avec la m\xE9thode du "),i(l,{to:"/articles/le-design-thinking"},{default:p(()=>[s("design thinking")]),_:1}),s(" avec le double diamant. Dans la phase exploration, nous avons cartographi\xE9, l'existant : Dispositifs mus\xE9aux innovants, Application de vulgarisation et d'apprentissage, Contenu et dispositif portant sur la science de la Pal\xE9ontologie. "),k,D,s(" Nous avons r\xE9dig\xE9 un protocole d'entretien pour \xE9changer avec les professionnels de la mus\xE9ographie et de la pal\xE9ontologie, ces interviews ont \xE9t\xE9 men\xE9es en visioconf\xE9rence et les verbatims, id\xE9es et remarques \xE9mises ont \xE9t\xE9 consign\xE9es dans un tableau. "),F,R,s(" Nous avons \xE9galement men\xE9 du shadowing, en visitant les Mus\xE9es d'histoire naturelle de Paris, Lille et Bruxelles, nous avons pu observer les comportements, le type de publique et interroger certains visiteurs pour recueillir de la mati\xE8re sur la motivation et la perception des visiteurs. "),B,E,s(" Cette observation s'est suivie de plusieurs exercices d'id\xE9ations. \xC0 ce moment-ci, plusieurs pistes ont \xE9t\xE9 envisag\xE9es : construire une borne interactive, cr\xE9er un audioguide, concevoir une application de visite gamifi\xE9e... Le choix s'est port\xE9 sur cette derni\xE8re, ce dispositif permet de mettre en avant la sc\xE9nographie d\xE9j\xE0 existante de la galerie. D'autres exercices d'id\xE9ation, nous ont permis de choisir le contenu abord\xE9, est le mus\xE9e sur lequel nous allions travailler. "),T,z,s(" Le dispositif de notre projet \xE9tant \xE9tabli, nous nous sommes attel\xE9s \xE0 la r\xE9alisation de plusieurs prototypes papier pour proposer une logique de navigation et d\u2019interaction avec les activit\xE9s. La solution retenue \xE9tait la suivante : un \xE9cran d'onboarding pour pr\xE9senter l'application, suivie d'une carte avec les diff\xE9rentes activit\xE9s disponibles. Cette version a \xE9t\xE9 r\xE9alis\xE9e sur Figma pour \xEAtre test\xE9 dans une salle qui sch\xE9matise la galerie du mus\xE9e, pour simuler les d\xE9placements des utilisateurs. "),I,S,s(" Ces tests utilisateurs ont \xE9t\xE9 riches en apprentissage, nous les avons consign\xE9s et nous avons \xE9tablie des plans d'action pour parer au probl\xE8me rencontr\xE9 dans le V1 : "),A,G,H,s(" En janvier, nous sommes lanc\xE9s dans la Delivery, mais nous nous sommes vite rendus compte que ce n'\xE9tait pas la bonne m\xE9thode, il y avait trop d'inconnu et de risque de d\xE9velopper des parties qui n'aurait pas fonctionn\xE9 aupr\xE8s du public. Nous avions besoins de faire r\xE9guli\xE8rement des tests utilisateur et de l'id\xE9ation sur des parties de l'application. Nous nous sommes lanc\xE9s en Discovery, cette m\xE9thode permet de r\xE9duire les risques et les incertitudes gr\xE2ce aux design sprints et aux 6 phases (alignement, affinage, validation, recherche, id\xE9ation, prototypage). ")]),Y])])])])}}};export{W as default};
